import { useState, useEffect, useRef } from "react";

const LOGO_B64 = "data:image/png;base64,";

const EMAILJS_SERVICE_ID = "service_s23aydq";
const EMAILJS_TEMPLATE_ID = "template_owi5i5a";
const EMAILJS_PUBLIC_KEY = "cZ8kpvNBqT36IpT4V";
const LAKELAB_EMAIL = "lakelabcomercial@gmail.com";

const questions = [
  { id: "objetivo", label: "Qual é o principal objetivo de negócio agora?", options: [{ label: "Ainda estou tentando definir", score: 1 }, { label: "Crescer e atrair mais clientes", score: 2 }, { label: "Consolidar a marca no mercado", score: 3 }, { label: "Expandir ou reinventar o negócio", score: 4 }] },
  { id: "aquisicao", label: "Como seus clientes chegam até você hoje?", options: [{ label: "Principalmente por indicação boca a boca", score: 1 }, { label: "Redes sociais, mas sem estratégia clara", score: 2 }, { label: "Mix de canais, com algum controle", score: 3 }, { label: "Tenho canais definidos e acompanho resultados", score: 4 }] },
  { id: "concorrentes", label: "Você conhece bem seus concorrentes?", options: [{ label: "Não tenho isso mapeado", score: 1 }, { label: "Conheço alguns, mas não analiso", score: 2 }, { label: "Acompanho o mercado com frequência", score: 3 }, { label: "Tenho análise competitiva estruturada", score: 4 }] },
  { id: "identidade", label: "Sua identidade visual representa bem a marca?", options: [{ label: "Não tenho identidade definida", score: 1 }, { label: "Tenho algo básico, mas não me representa bem", score: 2 }, { label: "Tenho identidade, mas precisa evoluir", score: 3 }, { label: "Identidade sólida e consistente em todos os pontos", score: 4 }] },
  { id: "metricas", label: "Você acompanha métricas de marketing regularmente?", options: [{ label: "Não acompanho quase nada", score: 1 }, { label: "Olho às vezes, sem rotina definida", score: 2 }, { label: "Acompanho algumas métricas mensalmente", score: 3 }, { label: "Tenho dashboard e reviso com frequência", score: 4 }] },
  { id: "agencia", label: "Já trabalhou com agência ou consultor antes?", options: [{ label: "Nunca", score: 2 }, { label: "Sim, mas os resultados foram fracos", score: 1 }, { label: "Sim, com resultados parciais", score: 3 }, { label: "Sim, tive boa experiência", score: 4 }] },
  { id: "desafio", label: "Qual é o maior desafio ainda não resolvido?", options: [{ label: "Não sei por onde começar", score: 1 }, { label: "Gerar mais visibilidade e alcance", score: 2 }, { label: "Converter o interesse em vendas", score: 3 }, { label: "Escalar o que já funciona", score: 4 }] },
];

const levels = [
  { max: 30, label: "Ponto de Partida", sublabel: "A marca ainda está encontrando sua voz.", description: "Este é um momento de fundação — o mais importante agora é não pular etapas. Antes de investir em tráfego ou campanhas, é preciso construir uma base sólida: identidade clara, posicionamento definido e canais escolhidos com intenção.", nextStep: "O próximo passo ideal é um trabalho de branding e identidade visual para dar consistência à marca antes de qualquer esforço de visibilidade.", bars: 1 },
  { max: 55, label: "Em Construção", sublabel: "Há base, mas ainda faltam consistência e direção.", description: "A marca tem presença, mas os esforços ainda são dispersos — cada canal fala de um jeito e fica difícil saber o que realmente funciona. O foco agora é criar coerência entre identidade, canais e objetivos de negócio.", nextStep: "O próximo passo ideal é estruturar a estratégia de marketing com clareza de canais, mensagem e metas — e começar a acompanhar os números de verdade.", bars: 2 },
  { max: 75, label: "Em Aceleração", sublabel: "A marca sabe o que quer. Precisa de método.", description: "Existe clareza de propósito e alguma estrutura funcionando. O desafio agora é sistematizar o que já funciona, eliminar o que dispersa energia e criar processos que escalam sem depender de improviso.", nextStep: "O próximo passo ideal é aprofundar a gestão de performance — otimizar campanhas, entender melhor o funil de aquisição e usar os dados para tomar decisões com mais precisão.", bars: 3 },
  { max: 100, label: "Maturidade Estratégica", sublabel: "Marca estruturada, pronta para crescer com inteligência.", description: "A base está construída e os processos funcionam. O diferencial agora está em sofisticar a experiência da marca, explorar novos canais com segurança e usar dados para antecipar movimentos ao invés de só reagir.", nextStep: "O próximo passo ideal é uma auditoria completa para identificar gargalos e oportunidades ainda não exploradas — e elevar o patamar da estratégia.", bars: 4 },
];

const getLevel = (pct) => levels.find((l) => pct <= l.max) || levels[3];

const BLUE = "#010fa2";
const BLUE_LIGHT = "#EEF2FF";
const BLACK = "#171717";
const GRAY = "#171717";
const BORDER = "#E5E7EB";

const inputStyle = { width: "100%", background: "transparent", border: "none", borderBottom: `1px solid ${BORDER}`, color: BLACK, fontSize: "1rem", padding: "0.75rem 0", outline: "none", fontFamily: "inherit", boxSizing: "border-box" };
const labelStyle = { fontSize: "0.72rem", letterSpacing: "0.18em", color: GRAY, textTransform: "uppercase", display: "block", marginBottom: "0.4rem" };

async function sendEmail(to, name, subject, message) {
  await fetch("https://api.emailjs.com/api/v1.0/email/send", {
    method: "POST",
    headers: { "Content-Type": "application/json" },
    body: JSON.stringify({
      service_id: EMAILJS_SERVICE_ID,
      template_id: EMAILJS_TEMPLATE_ID,
      user_id: EMAILJS_PUBLIC_KEY,
      template_params: { to_email: to, name, email: to, title: subject, message },
    }),
  });
}

export default function DiagnosticoMarca() {
  const [step, setStep] = useState("cover");
  const [lead, setLead] = useState({ empresa: "", funcionarios: "", segmento: "", segmentoOutro: "", site: "" });
  const [contact, setContact] = useState({ nome: "", email: "", whatsapp: "" });
  const [answers, setAnswers] = useState({});
  const [current, setCurrent] = useState(0);

  const [displayText, setDisplayText] = useState("");
  const fullTitle = "Diagnóstico de Marca";
  const typingRef = useRef(null);

  useEffect(() => {
    const typeSpeed = 80;
    const pauseAfter = 1800;
    const deleteSpeed = 40;
    let i = 0;
    let deleting = false;

    const tick = () => {
      if (!deleting) {
        i++;
        setDisplayText(fullTitle.slice(0, i));
        if (i === fullTitle.length) {
          typingRef.current = setTimeout(() => { deleting = true; tick(); }, pauseAfter);
          return;
        }
      } else {
        i--;
        setDisplayText(fullTitle.slice(0, i));
        if (i === 0) { deleting = false; }
      }
      typingRef.current = setTimeout(tick, deleting ? deleteSpeed : typeSpeed);
    };

    typingRef.current = setTimeout(tick, 300);
    return () => clearTimeout(typingRef.current);
  }, []);

  const [sending, setSending] = useState(false);
  const [sendError, setSendError] = useState(false);
  const [usedEmails, setUsedEmails] = useState([]);
  const [duplicateEmail, setDuplicateEmail] = useState(false);

  const totalQuestions = questions.length;
  const totalScore = Object.values(answers).reduce((a, b) => a + b, 0);
  const pct = Math.round((totalScore / (totalQuestions * 4)) * 100);
  const level = getLevel(pct);

  const handleAnswer = (score) => {
    const newAnswers = { ...answers, [questions[current].id]: score };
    setAnswers(newAnswers);
    if (current < totalQuestions - 1) setCurrent(current + 1);
    else setStep("gate");
  };

  const handleSubmit = async () => {
    if (!contact.nome.trim() || !contact.email.trim() || !contact.whatsapp.trim()) return;
    if (usedEmails.includes(contact.email.toLowerCase())) {
      setDuplicateEmail(true);
      return;
    }
    setSending(true);
    setSendError(false);
    setDuplicateEmail(false);

    const breakdown = questions.map((q) => {
      const opted = q.options.find(o => o.score === answers[q.id]);
      return `• ${q.label}\n  → ${opted?.label || "-"}`;
    }).join("\n\n");

    const msgToLakelab = `Novo lead via Diagnóstico de Marca\n\nNome: ${contact.nome}\nEmail: ${contact.email}\nWhatsApp: ${contact.whatsapp}\nEmpresa: ${lead.empresa}\nFuncionários: ${lead.funcionarios || "não informado"}\nSegmento: ${lead.segmento === "Outro" ? lead.segmentoOutro : lead.segmento || "não informado"}\nSite: ${lead.site || "não informado"}\n\nResultado: ${level.label} (${pct}% de maturidade)\n\nRespostas:\n${breakdown}`;
    const msgToLead = `Olá, ${contact.nome}!\n\nAqui está o diagnóstico de marca da ${lead.empresa}.\n\n━━━━━━━━━━━━━━━━━━━━━\nRESULTADO: ${level.label}\nMaturidade de marca: ${pct}%\n━━━━━━━━━━━━━━━━━━━━━\n\n${level.sublabel}\n\n${level.description}\n\nPRÓXIMO PASSO RECOMENDADO:\n${level.nextStep}\n\nEm breve entraremos em contato.\n\nAtenciosamente,\nLakeLab Agency`;

    setStep("result");
    setSending(false);
    setUsedEmails(prev => [...prev, contact.email.toLowerCase()]);
    Promise.all([
      sendEmail(LAKELAB_EMAIL, contact.nome, `Lead: ${contact.nome} — ${lead.empresa}`, msgToLakelab),
      sendEmail(contact.email, contact.nome, `Seu diagnóstico está pronto, ${contact.nome}`, msgToLead),
    ]).catch(() => setSendError(true));
  };

  const reset = () => { setStep("cover"); setAnswers({}); setCurrent(0); setLead({ empresa: "", funcionarios: "", segmento: "", segmentoOutro: "", site: "" }); setContact({ nome: "", email: "", whatsapp: "" }); setSendError(false); };
  const canStart = lead.empresa.trim() && lead.funcionarios && lead.segmento && (lead.segmento !== "Outro" || lead.segmentoOutro.trim());
  const canSubmit = contact.nome.trim() && contact.email.trim() && contact.whatsapp.trim();

  const btnStyle = (active) => ({
    width: "100%", background: active ? BLUE : BORDER, color: active ? "#fff" : GRAY,
    border: "none", padding: "0.9rem", fontSize: "0.8rem", fontWeight: "600",
    letterSpacing: "0.08em", textTransform: "uppercase", cursor: active ? "pointer" : "default",
    fontFamily: "inherit", transition: "all 0.2s ease", borderRadius: "2px",
  });

  return (
    <div style={{ minHeight: "100vh", background: "#FEFEFE", fontFamily: "'Satoshi', 'Helvetica Neue', sans-serif", color: BLACK, display: "flex", flexDirection: "column", alignItems: "center", justifyContent: "center", padding: "2rem" }}>

      {step === "cover" && (
        <div style={{ position: "fixed", top: 0, left: 0, width: "100%", height: "100%", display: "flex", flexDirection: "column", alignItems: "center", justifyContent: "center", overflow: "hidden", background: "#FEFEFE" }}>
        <div style={{ maxWidth: 680, width: "100%", textAlign: "center", display: "flex", flexDirection: "column", alignItems: "center", gap: "1.5rem", position: "relative", zIndex: 1, padding: "0 2rem", animation: "fadeIn 0.8s ease", marginBottom: "65px" }}>
          
          <a href="https://www.lakelab.com.br" target="_blank" rel="noreferrer" style={{ display: "block", margin: "0 auto" }}>
            <img src={LOGO_B64} alt="LakeLab" style={{ height: 52, display: "block" }} />
          </a>

          <h1 style={{ fontSize: "2.6rem", fontWeight: "800", color: BLACK, letterSpacing: "-0.05em", lineHeight: 1.1, fontFamily: "'Cabinet Grotesk', sans-serif" }}>
              Diagnóstico<br />de Marca
            </h1>

          {/* CTA */}
          <button onClick={() => setStep("intro")} style={{
            background: BLUE, color: "#fff", border: "none",
            padding: "1rem 2.5rem", fontSize: "0.85rem", fontWeight: "600",
            letterSpacing: "0.1em", textTransform: "uppercase",
            cursor: "pointer", fontFamily: "inherit", borderRadius: "2px",
            display: "flex", alignItems: "center", gap: "0.6rem",
            transition: "opacity 0.2s ease",
          }}
            onMouseEnter={e => e.currentTarget.style.opacity = "0.85"}
            onMouseLeave={e => e.currentTarget.style.opacity = "1"}
          >
            Iniciar diagnóstico
            <svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round">
              <path d="M5 12h14M12 5l7 7-7 7"/>
            </svg>
          </button>

          {/* Meta info */}
          <div style={{ display: "flex", gap: "2rem", justifyContent: "center" }}>
            <div style={{ textAlign: "center" }}>
              <p style={{ fontSize: "1.6rem", fontWeight: "800", color: BLUE, fontFamily: "'Cabinet Grotesk', sans-serif", lineHeight: 1 }}>7</p>
              <p style={{ fontSize: "0.75rem", color: GRAY, marginTop: "0.2rem" }}>perguntas</p>
            </div>
            <div style={{ width: "1px", background: "#E5E7EB" }} />
            <div style={{ textAlign: "center" }}>
              <p style={{ fontSize: "1.6rem", fontWeight: "800", color: BLUE, fontFamily: "'Cabinet Grotesk', sans-serif", lineHeight: 1 }}>2</p>
              <p style={{ fontSize: "0.75rem", color: GRAY, marginTop: "0.2rem" }}>minutos</p>
            </div>
            <div style={{ width: "1px", background: "#E5E7EB" }} />
            <div style={{ textAlign: "center" }}>
              <p style={{ fontSize: "1.6rem", fontWeight: "800", color: BLUE, fontFamily: "'Cabinet Grotesk', sans-serif", lineHeight: 1 }}>100%</p>
              <p style={{ fontSize: "0.75rem", color: GRAY, marginTop: "0.2rem" }}>gratuito</p>
            </div>
          </div>
          <p style={{ fontSize: "0.75rem", color: "#AAAAAA", marginTop: "1rem", lineHeight: 1.6, textAlign: "center", maxWidth: 420 }}>
            Suas informações são utilizadas exclusivamente para fins de diagnóstico e contato comercial. Ao continuar, você concorda com nossa{" "}
            <a href="https://www.lakelab.com.br" target="_blank" rel="noreferrer" style={{ color: BLUE, textDecoration: "underline" }}>Política de Privacidade</a>.
          </p>
        </div>

        {/* Wave animation at bottom of cover */}
        <div style={{
          position: "absolute", bottom: 0, left: 0, width: "100%",
          height: 120, pointerEvents: "none", zIndex: 0, overflow: "hidden",
        }}>
          <svg viewBox="0 0 1440 160" preserveAspectRatio="none"
            style={{ width: "100%", height: "100%", display: "block" }}>
            <defs>
              <linearGradient id="waveGrad" x1="0" y1="0" x2="0" y2="1">
                <stop offset="0%" stopColor={BLUE} stopOpacity="0.18" />
                <stop offset="100%" stopColor={BLUE} stopOpacity="0.06" />
              </linearGradient>
            </defs>
            <path className="wave wave1" fill="url(#waveGrad)"
              d="M0,80 C180,40 360,120 540,80 C720,40 900,120 1080,80 C1260,40 1380,100 1440,80 L1440,160 L0,160 Z" />
            <path className="wave wave2" fill={BLUE} fillOpacity="0.08"
              d="M0,100 C200,60 400,130 600,100 C800,70 1000,130 1200,100 C1320,80 1400,110 1440,100 L1440,160 L0,160 Z" />
            <path className="wave wave3" fill={BLUE} fillOpacity="0.12"
              d="M0,120 C240,90 480,145 720,120 C960,95 1200,145 1440,120 L1440,160 L0,160 Z" />
          </svg>
        </div>
        </div>
      )}

      {step === "intro" && (
        <div style={{ maxWidth: 680, width: "100%", animation: "fadeIn 0.5s ease" }}>
          <img src={LOGO_B64} alt="LakeLab" style={{ height: 48, marginBottom: "2rem", display: "block", maxWidth: 220 }} />
          <h1 style={{ fontSize: "2.2rem", fontWeight: "800", lineHeight: 1.2, marginBottom: "0.75rem", color: BLACK, letterSpacing: "-0.04em", fontFamily: "'Cabinet Grotesk', sans-serif" }}>
            Você está a um passo de aumentar o faturamento da sua empresa.
          </h1>
          <p style={{ color: GRAY, fontSize: "1.05rem", lineHeight: 1.75, marginBottom: "2.5rem" }}>Avalie a maturidade da sua marca em 7 perguntas e descubra onde investir para crescer.</p>
          <div style={{ display: "flex", flexDirection: "column", gap: "1.5rem", marginBottom: "2rem" }}>
            <div><label style={labelStyle}>Nome da empresa *</label><input style={inputStyle} placeholder="Ex: Studio Verve" value={lead.empresa} onChange={e => setLead(p => ({ ...p, empresa: e.target.value }))} /></div>
            <div>
              <label style={labelStyle}>Número de funcionários</label>
              <select style={{...inputStyle, cursor: "pointer", color: lead.funcionarios ? BLACK : GRAY}} value={lead.funcionarios} onChange={e => setLead(p => ({ ...p, funcionarios: e.target.value }))}>
                <option value="" style={{ color: GRAY }}>Selecione</option>
                <option value="1">Só eu (MEI / solo)</option>
                <option value="2-5">2 a 5</option>
                <option value="6-20">6 a 20</option>
                <option value="21-50">21 a 50</option>
                <option value="50+">Mais de 50</option>
              </select>
            </div>
            <div>
              <label style={labelStyle}>Segmento</label>
              <select style={{...inputStyle, cursor: "pointer", color: lead.segmento ? BLACK : GRAY}} value={lead.segmento} onChange={e => setLead(p => ({ ...p, segmento: e.target.value }))}>
                <option value="" style={{ color: GRAY }}>Selecione</option>
                <option>Agências e Marketing</option>
                <option>Alimentação e Bebidas</option>
                <option>Arquitetura e Interiores</option>
                <option>Beleza e Estética</option>
                <option>Consultoria e Gestão</option>
                <option>Construção e Reformas</option>
                <option>Educação e Treinamentos</option>
                <option>Eventos e Entretenimento</option>
                <option>Financeiro e Contabilidade</option>
                <option>Jurídico</option>
                <option>Moda e Varejo</option>
                <option>Saúde e Bem-estar</option>
                <option>Serviços B2B</option>
                <option>Tecnologia e Software</option>
                <option>Turismo e Hotelaria</option>
                <option>Outro</option>
              </select>
              {lead.segmento === "Outro" && (
                <input style={{...inputStyle, marginTop: "0.75rem"}} placeholder="Qual é o seu segmento?" value={lead.segmentoOutro} onChange={e => setLead(p => ({ ...p, segmentoOutro: e.target.value }))} />
              )}
            </div>
            <div><label style={labelStyle}>Site (se houver)</label><input style={inputStyle} placeholder="Ex: minhaempresa.com.br" value={lead.site} onChange={e => setLead(p => ({ ...p, site: e.target.value }))} /></div>
          </div>
          <button onClick={() => canStart && setStep("questions")} style={btnStyle(canStart)}>Próximo →</button>
        </div>
      )}

      {step === "questions" && (
        <div style={{ maxWidth: 720, width: "100%", animation: "fadeIn 0.4s ease" }}>
          <div style={{ marginBottom: "3rem" }}>
            <div style={{ display: "flex", justifyContent: "space-between", marginBottom: "0.5rem" }}>
              <span style={{ fontSize: "0.7rem", color: BLUE, fontWeight: "600" }}>{current + 1} / {totalQuestions}</span>
              <span style={{ fontSize: "0.7rem", color: GRAY }}>{lead.empresa}</span>
            </div>
            <div style={{ height: "2px", background: BORDER, borderRadius: "2px" }}>
              <div style={{ height: "100%", width: `${(current / totalQuestions) * 100}%`, background: BLUE, borderRadius: "2px", transition: "width 0.4s ease" }} />
            </div>
          </div>
          <h2 style={{ fontSize: "1.8rem", fontWeight: "800", lineHeight: 1.35, marginBottom: "2rem", color: BLACK, letterSpacing: "-0.03em", fontFamily: "'Cabinet Grotesk', sans-serif" }}>{questions[current].label}</h2>
          <div style={{ display: "flex", flexDirection: "column", gap: "0.6rem" }}>
            {questions[current].options.map((opt, i) => (
              <button key={i} onClick={() => handleAnswer(opt.score)}
                style={{ background: "#FEFEFE", border: `1px solid ${BORDER}`, color: BLACK, padding: "0.9rem 1.25rem", textAlign: "left", cursor: "pointer", fontFamily: "inherit", fontSize: "1rem", lineHeight: 1.6, transition: "all 0.15s ease", borderRadius: "2px" }}
                onMouseEnter={e => { e.currentTarget.style.borderColor = BLUE; e.currentTarget.style.background = BLUE_LIGHT; e.currentTarget.style.color = BLUE; }}
                onMouseLeave={e => { e.currentTarget.style.borderColor = BORDER; e.currentTarget.style.background = "#fff"; e.currentTarget.style.color = BLACK; }}
              >{opt.label}</button>
            ))}
          </div>
          {current > 0 && <button onClick={() => setCurrent(current - 1)} style={{ marginTop: "1.5rem", background: "transparent", border: "none", color: GRAY, cursor: "pointer", fontFamily: "inherit", fontSize: "0.8rem" }}>← voltar</button>}
        </div>
      )}

      {step === "gate" && (
        <div style={{ maxWidth: 640, width: "100%", animation: "fadeIn 0.5s ease" }}>
          <a href="https://www.lakelab.com.br" target="_blank" rel="noreferrer" style={{ display: "block", marginBottom: "1.5rem" }}>
            <img src={LOGO_B64} alt="LakeLab" style={{ height: 36, display: "block", maxWidth: 180 }} />
          </a>
          <p style={{ fontSize: "0.65rem", letterSpacing: "0.22em", color: BLUE, textTransform: "uppercase", marginBottom: "1rem" }}>Diagnóstico concluído</p>
          <h2 style={{ fontSize: "2.2rem", fontWeight: "800", color: BLACK, marginBottom: "0.6rem", letterSpacing: "-0.04em", fontFamily: "'Cabinet Grotesk', sans-serif" }}>Seu resultado está pronto.</h2>
          <p style={{ color: GRAY, fontSize: "1.05rem", lineHeight: 1.75, marginBottom: "2rem" }}>Preencha os dados abaixo para receber o diagnóstico no seu email.</p>
          <div style={{ display: "flex", flexDirection: "column", gap: "1.5rem", marginBottom: "1.5rem" }}>
            <div><label style={labelStyle}>Seu nome *</label><input style={inputStyle} placeholder="Ex: Marina Lima" value={contact.nome} onChange={e => setContact(p => ({ ...p, nome: e.target.value }))} /></div>
            <div><label style={labelStyle}>E-mail *</label><input style={inputStyle} placeholder="Ex: marina@empresa.com" type="email" value={contact.email} onChange={e => setContact(p => ({ ...p, email: e.target.value }))} /></div>
            <div><label style={labelStyle}>WhatsApp *</label><input style={inputStyle} placeholder="Ex: (81) 99999-0000" value={contact.whatsapp} onChange={e => setContact(p => ({ ...p, whatsapp: e.target.value }))} /></div>
          </div>
          {sendError && <p style={{ color: "#DC2626", fontSize: "0.8rem", marginBottom: "1rem" }}>Erro ao enviar. Verifique sua conexão e tente novamente.</p>}
          {duplicateEmail && <p style={{ color: "#DC2626", fontSize: "0.8rem", marginBottom: "1rem" }}>Este e-mail já realizou um diagnóstico. Cada e-mail permite apenas 1 diagnóstico.</p>}
          <button onClick={handleSubmit} disabled={!canSubmit || sending} style={btnStyle(canSubmit && !sending)}>{sending ? "Enviando..." : "Ver meu diagnóstico →"}</button>
          <p style={{ marginTop: "0.75rem", fontSize: "0.7rem", color: "#888888", textAlign: "center" }}>Cada e-mail permite apenas 1 diagnóstico. Seus dados não serão compartilhados com terceiros.</p>
        </div>
      )}

      {step === "result" && (
        <div style={{ maxWidth: 760, width: "100%", animation: "fadeIn 0.7s ease" }}>
          <a href="https://www.lakelab.com.br" target="_blank" rel="noreferrer" style={{ display: "block", marginBottom: "2rem" }}>
            <img src={LOGO_B64} alt="LakeLab" style={{ height: 44, display: "block", maxWidth: 220 }} />
          </a>
          <p style={{ color: GRAY, fontSize: "0.8rem", marginBottom: "0.2rem" }}>{lead.empresa}</p>
          <h1 style={{ fontSize: "3rem", fontWeight: "800", color: BLACK, marginBottom: "0.4rem", letterSpacing: "-0.05em", lineHeight: 1.1, fontFamily: "'Cabinet Grotesk', sans-serif" }}>{level.label}</h1>
          <p style={{ color: BLUE, fontSize: "1.05rem", marginBottom: "2rem", fontWeight: "500" }}>{level.sublabel}</p>

          <div style={{ display: "flex", alignItems: "flex-end", gap: "5px", marginBottom: "2rem" }}>
            {[1, 2, 3, 4].map(bar => (
              <div key={bar} style={{ width: 24, height: 14 + bar * 12, background: bar <= level.bars ? BLUE : BLUE_LIGHT, borderRadius: "1px" }} />
            ))}
            <span style={{ marginLeft: "0.75rem", fontSize: "2.8rem", fontWeight: "800", color: BLACK, letterSpacing: "-0.04em", lineHeight: 1 }}>
              {pct}<span style={{ fontSize: "1rem", color: GRAY, fontWeight: "400" }}>%</span>
            </span>
          </div>

          <div style={{ height: "1px", background: BORDER, marginBottom: "1.75rem" }} />
          <p style={{ color: GRAY, fontSize: "1rem", lineHeight: 1.85, marginBottom: "1.5rem" }}>{level.description}</p>

          <div style={{ background: BLUE_LIGHT, borderLeft: `3px solid ${BLUE}`, padding: "1.1rem 1.25rem", marginBottom: "2rem", borderRadius: "0 2px 2px 0" }}>
            <p style={{ fontSize: "0.6rem", letterSpacing: "0.18em", color: BLUE, textTransform: "uppercase", marginBottom: "0.4rem", fontWeight: "600" }}>Próximo passo recomendado</p>
            <p style={{ color: BLACK, fontSize: "1rem", lineHeight: 1.75, margin: 0 }}>{level.nextStep}</p>
          </div>

          <p style={{ fontSize: "0.6rem", letterSpacing: "0.18em", color: GRAY, textTransform: "uppercase", marginBottom: "0.9rem", fontWeight: "600" }}>Visão por dimensão</p>
          <div style={{ display: "flex", flexDirection: "column", gap: "0.65rem", marginBottom: "2rem" }}>
            {questions.map(q => {
              const score = answers[q.id] || 0;
              const pctQ = (score / 4) * 100;
              return (
                <div key={q.id} style={{ display: "flex", alignItems: "center", gap: "0.75rem" }}>
                  <p style={{ fontSize: "0.85rem", color: GRAY, width: 220, flexShrink: 0, lineHeight: 1.4 }}>{q.label.length > 40 ? q.label.slice(0, 40) + "…" : q.label}</p>
                  <div style={{ flex: 1, height: "3px", background: BLUE_LIGHT, borderRadius: "2px", position: "relative" }}>
                    <div style={{ position: "absolute", left: 0, top: 0, height: "100%", width: `${pctQ}%`, background: pctQ >= 75 ? BLUE : pctQ >= 50 ? "#93A8EC" : "#C7D2F8", borderRadius: "2px" }} />
                  </div>
                  <p style={{ fontSize: "0.65rem", color: GRAY, width: 20, textAlign: "right" }}>{score}/4</p>
                </div>
              );
            })}
          </div>

          <div style={{ background: "#F9FAFB", border: `1px solid ${BORDER}`, padding: "0.9rem 1.1rem", borderRadius: "2px", marginBottom: "2rem" }}>
            <p style={{ fontSize: "0.8rem", color: GRAY, margin: 0 }}>
              📩 Um resumo foi enviado para <strong style={{ color: BLACK }}>{contact.email}</strong>. Caso não encontre, verifique sua caixa de spam.
            </p>
          </div>

          <div style={{ display: "flex", justifyContent: "center", paddingTop: "1rem" }}>
            <button onClick={reset} style={{ background: "transparent", border: `1px solid ${BORDER}`, color: GRAY, padding: "0.6rem 1.5rem", cursor: "pointer", fontFamily: "inherit", fontSize: "0.75rem", letterSpacing: "0.08em", textTransform: "uppercase", borderRadius: "2px" }}>Novo diagnóstico</button>
          </div>
        </div>
      )}

      <style>{`
        @import url('https://api.fontshare.com/v2/css?f[]=cabinet-grotesk@800,700,500&f[]=satoshi@400,500&display=swap');
        @keyframes fadeIn { from { opacity: 0; transform: translateY(10px); } to { opacity: 1; transform: translateY(0); } }
        @keyframes blink { 0%, 100% { opacity: 1; } 50% { opacity: 0; } }
        @keyframes waveMove1 { 0% { transform: translateX(0); } 50% { transform: translateX(-60px); } 100% { transform: translateX(0); } }
        @keyframes waveMove2 { 0% { transform: translateX(0); } 50% { transform: translateX(50px); } 100% { transform: translateX(0); } }
        @keyframes waveMove3 { 0% { transform: translateX(0); } 50% { transform: translateX(-40px); } 100% { transform: translateX(0); } }
        @keyframes waveBob { 0%, 100% { transform: translateY(0); } 50% { transform: translateY(-12px); } }
        .wave { transform-origin: center; }
        .wave1 { animation: waveMove1 5s ease-in-out infinite, waveBob 4s ease-in-out infinite; }
        .wave2 { animation: waveMove2 6s ease-in-out infinite, waveBob 5s ease-in-out infinite 0.5s; }
        .wave3 { animation: waveMove3 7s ease-in-out infinite, waveBob 6s ease-in-out infinite 1s; }
        @keyframes slideRight { 0% { transform: translateX(-30px); opacity: 0; } 20% { transform: translateX(0); opacity: 1; } 80% { transform: translateX(0); opacity: 1; } 100% { transform: translateX(30px); opacity: 0; } }
        .logo-slide { animation: slideRight 2.5s ease-in-out infinite; }
        input::placeholder { color: #D1D5DB; }
        input:focus { border-bottom-color: ${BLUE} !important; }
        select option { color: #0A0A0A; }
        select:invalid { color: #D1D5DB; }
        * { box-sizing: border-box; }
        .font-heading { font-family: 'Cabinet Grotesk', sans-serif; }
        .font-body { font-family: 'Satoshi', sans-serif; }
      `}</style>
    </div>
  );
}
